// ── Generate LaTeX (Jake's Resume format) ──────────────────────────────────
const body = items[0].json.body || items[0].json || {};
const resume = body.tailored_resume;

function esc(str) {
  if (str === null || str === undefined) return '';
  return String(str)
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/&/g, '\\&')
    .replace(/%/g, '\\%')
    .replace(/_/g, '\\_')
    .replace(/#/g, '\\#')
    .replace(/\$/g, '\\$')
    .replace(/\{/g, '\\{')
    .replace(/\}/g, '\\}')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}');
}

const contact = resume.contact || {};
const name = esc(contact.name || 'Your Name');
const email = esc(contact.email || '');
const phone = esc(contact.phone || '');
const linkedin = esc(contact.linkedin || '');
const github = esc(contact.github || '');

// Build contact line parts
const contactParts = [];
if (phone) contactParts.push(phone);
if (email) contactParts.push(`\\href{mailto:${email}}{${email}}`);
if (linkedin) contactParts.push(`\\href{https://${linkedin}}{${linkedin}}`);
if (github) contactParts.push(`\\href{https://${github}}{${github}}`);
const contactLine = contactParts.join(' $|$ ');

// ── Education ────────────────────────────────────────────────────────────────
let educationSection = '';
const education = resume.education || [];
if (education.length > 0) {
  educationSection = `
%-----------EDUCATION-----------
\\section{Education}
  \\resumeSubHeadingListStart
`;
  for (const edu of education) {
    const gpaStr = edu.gpa ? `, GPA: ${esc(String(edu.gpa))}` : '';
    educationSection += `    \\resumeSubheading
      {${esc(edu.institution || '')}}{${esc(edu.dates || '')}}
      {${esc(edu.degree || '')}${gpaStr}}{}
`;
  }
  educationSection += `  \\resumeSubHeadingListEnd
`;
}

// ── Experience ───────────────────────────────────────────────────────────────
let experienceSection = '';
const experience = resume.experience || [];
if (experience.length > 0) {
  experienceSection = `
%-----------EXPERIENCE-----------
\\section{Experience}
  \\resumeSubHeadingListStart
`;
  for (const exp of experience) {
    experienceSection += `    \\resumeSubheading
      {${esc(exp.title || '')}}{${esc(exp.dates || '')}}
      {${esc(exp.company || '')}}{}
      \\resumeItemListStart
`;
    for (const bullet of (exp.bullets || [])) {
      experienceSection += `        \\resumeItem{${esc(bullet)}}
`;
    }
    experienceSection += `      \\resumeItemListEnd
`;
  }
  experienceSection += `  \\resumeSubHeadingListEnd
`;
}

// ── Projects ─────────────────────────────────────────────────────────────────
let projectsSection = '';
const projects = resume.projects || [];
if (projects.length > 0) {
  projectsSection = `
%-----------PROJECTS-----------
\\section{Projects}
  \\resumeSubHeadingListStart
`;
  for (const proj of projects) {
    const techStr = (proj.tech || []).map(t => esc(t)).join(', ');
    const heading = techStr
      ? `\\textbf{${esc(proj.name || '')}} $|$ \\emph{\\small{${techStr}}}`
      : `\\textbf{${esc(proj.name || '')}}`;
    projectsSection += `    \\resumeProjectHeading
      {${heading}}{}
      \\resumeItemListStart
`;
    for (const bullet of (proj.bullets || [])) {
      projectsSection += `        \\resumeItem{${esc(bullet)}}
`;
    }
    projectsSection += `      \\resumeItemListEnd
`;
  }
  projectsSection += `  \\resumeSubHeadingListEnd
`;
}

// ── Skills ───────────────────────────────────────────────────────────────────
let skillsSection = '';
const skills = resume.skills || [];
if (skills.length > 0) {
  skillsSection = `
%-----------TECHNICAL SKILLS-----------
\\section{Technical Skills}
 \\begin{itemize}[leftmargin=0.15in, label={}]
    \\small{\\item{
`;
  const skillLines = skills.map(s => {
    const cat = esc(s.category || '');
    const itemList = (s.items || []).map(i => esc(i)).join(', ');
    return `     \\textbf{${cat}}{: ${itemList}}`;
  });
  skillsSection += skillLines.join(' \\\\\
') + `
    }}
 \\end{itemize}
`;
}

// ── Summary ──────────────────────────────────────────────────────────────────
let summarySection = '';
if (resume.summary) {
  summarySection = `
%-----------SUMMARY-----------
\\section{Summary}
 \\begin{itemize}[leftmargin=0.15in, label={}]
    \\small{\\item{${esc(resume.summary)}}}
 \\end{itemize}
`;
}

// ── Assemble document ────────────────────────────────────────────────────────
const tex = `\\documentclass[letterpaper,11pt]{article}
\\usepackage{latexsym}
\\usepackage[empty]{fullpage}
\\usepackage{titlesec}
\\usepackage{marvosym}
\\usepackage[usenames,dvipsnames]{color}
\\usepackage{verbatim}
\\usepackage{enumitem}
\\usepackage[hidelinks]{hyperref}
\\usepackage{fancyhdr}
\\usepackage[english]{babel}
\\usepackage{tabularx}
\\input{glyphtounicode}
\\pagestyle{fancy}\\fancyhf{}\\fancyfoot{}
\\renewcommand{\\headrulewidth}{0pt}\\renewcommand{\\footrulewidth}{0pt}
\\addtolength{\\oddsidemargin}{-0.5in}\\addtolength{\\evensidemargin}{-0.5in}
\\addtolength{\\textwidth}{1in}\\addtolength{\\topmargin}{-.5in}\\addtolength{\\textheight}{1.0in}
\\urlstyle{same}\\raggedbottom\\raggedright\\setlength{\\tabcolsep}{0in}
\\titleformat{\\section}{\\vspace{-4pt}\\scshape\\raggedright\\large}{}{0em}{}[\\color{black}\\titlerule \\vspace{-5pt}]
\\pdfgentounicode=1
\\newcommand{\\resumeItem}[1]{\\item\\small{{#1 \\vspace{-2pt}}}}
\\newcommand{\\resumeSubheading}[4]{\\vspace{-2pt}\\item\\begin{tabular*}{0.97\\textwidth}[t]{l@{\\extracolsep{\\fill}}r}\\textbf{#1} & #2 \\\\\\textit{\\small#3} & \\textit{\\small #4} \\\\\\end{tabular*}\\vspace{-7pt}}
\\newcommand{\\resumeProjectHeading}[2]{\\item\\begin{tabular*}{0.97\\textwidth}{l@{\\extracolsep{\\fill}}r}\\small#1 & #2 \\\\\\end{tabular*}\\vspace{-7pt}}
\\renewcommand\\labelitemii{$\\vcenter{\\hbox{\\tiny$\\bullet$}}$}
\\newcommand{\\resumeSubHeadingListStart}{\\begin{itemize}[leftmargin=0.15in, label={}]}
\\newcommand{\\resumeSubHeadingListEnd}{\\end{itemize}}
\\newcommand{\\resumeItemListStart}{\\begin{itemize}}
\\newcommand{\\resumeItemListEnd}{\\end{itemize}\\vspace{-5pt}}
\\begin{document}

%----------HEADING----------
\\begin{center}
    {\\Huge \\scshape ${name}} \\\\ \\vspace{1pt}
    \\small ${contactLine}
\\end{center}
${summarySection}${educationSection}${experienceSection}${projectsSection}${skillsSection}
\\end{document}
`;

return [{ json: { tex_source: tex } }];

const texSource = items[0].json.tex_source;
const b64 = Buffer.from(texSource).toString('base64');
return [{ json: { tex_source: texSource, tex_base64: b64 } }];

// Success path: PDF binary exists — convert to base64
const item = items[0];
const texSource = $('Base64 Encode TEX').item.json.tex_source;

// Find the binary key (usually 'data')
const binaryKey = Object.keys(item.binary || {})[0] || 'data';
const binaryData = item.binary[binaryKey];

let pdfBase64 = null;
if (binaryData && binaryData.data) {
  pdfBase64 = binaryData.data;
} else if (binaryData) {
  // Already base64 encoded string in some n8n versions
  pdfBase64 = binaryData.data || null;
}

return [{
  json: {
    tex_source: texSource,
    pdf_base64: pdfBase64,
    compile_error: null
  }
}];

// Error path: LaTeX compilation failed
const texSource = $('Base64 Encode TEX').item.json.tex_source;

return [{
  json: {
    tex_source: texSource,
    pdf_base64: null,
    compile_error: 'LaTeX compilation failed. Download .tex to fix in Overleaf.'
  }
}];
